<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Snake Game</title>
  <style>
    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      background-color: #0f172a;
      color: #f8fafc;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
      min-height: 100vh;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      padding: 20px;
    }

    .game-container {
      background-color: #1e293b;
      padding: 24px;
      border-radius: 16px;
      box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.5), 0 8px 10px -6px rgba(0, 0, 0, 0.5);
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 16px;
    }

    .header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      width: 100%;
      max-width: 400px;
    }

    .title {
      font-size: 24px;
      font-weight: 800;
      letter-spacing: 1px;
      color: #38bdf8;
      text-transform: uppercase;
    }

    .score-board {
      font-size: 18px;
      font-weight: 700;
      background-color: #0f172a;
      padding: 6px 16px;
      border-radius: 20px;
      border: 1px solid #334155;
      color: #f1f5f9;
    }

    .score-board span {
      color: #10b981;
    }

    #snake {
      width: 400px;
      height: 400px;
      background-color: #0f172a;
      border-radius: 8px;
      border: 2px solid #334155;
      display: block;
      box-shadow: inset 0 2px 4px 0 rgba(0, 0, 0, 0.6);
    }

    .controls {
      display: flex;
      gap: 12px;
      width: 100%;
      max-width: 400px;
    }

    button {
      flex: 1;
      padding: 10px 16px;
      font-size: 14px;
      font-weight: 700;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      transition: all 0.15s ease-in-out;
      text-transform: uppercase;
      letter-spacing: 0.5px;
    }

    #start {
      background-color: #10b981;
      color: #022c22;
    }

    #start:hover {
      background-color: #34d399;
      transform: translateY(-1px);
    }

    #pause {
      background-color: #f59e0b;
      color: #451a03;
    }

    #pause:hover {
      background-color: #fbbf24;
      transform: translateY(-1px);
    }

    #reset {
      background-color: #ef4444;
      color: #450a0a;
    }

    #reset:hover {
      background-color: #f87171;
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px);
    }

    .instructions {
      font-size: 12px;
      color: #64748b;
      text-align: center;
      margin-top: 4px;
    }
  </style>
</head>
<body>

  <div class="game-container">
    <div class="header">
      <div class="title">Snake</div>
      <div class="score-board">Score: <span id="score">0</span></div>
    </div>

    <canvas id="snake" width="400" height="400"></canvas>

    <div class="controls">
      <button id="start">Start</button>
      <button id="pause">Pause</button>
      <button id="reset">Reset</button>
    </div>

    <div class="instructions">
      Use Arrow Keys or WASD to steer
    </div>
  </div>

  <script>
    (function() {
      const GRID_SIZE = 20;

      let w = GRID_SIZE;
      let h = GRID_SIZE;
      let snakeSegments = [];
      let food = null;
      let currentDir = 'right';
      let pendingDir = null;
      let isAlive = true;
      let currentScore = 0;
      let timer = null;

      const OPPOSITES = {
        up: 'down',
        down: 'up',
        left: 'right',
        right: 'left'
      };

      function updateScoreUI() {
        const el = document.getElementById('score');
        if (el) el.textContent = currentScore;
      }

      function spawnFood() {
        const freeCells = [];
        for (let x = 0; x < w; x++) {
          for (let y = 0; y < h; y++) {
            let occupied = false;
            for (let k = 0; k < snakeSegments.length; k++) {
              if (snakeSegments[k][0] === x && snakeSegments[k][1] === y) {
                occupied = true;
                break;
              }
            }
            if (!occupied) {
              freeCells.push([x, y]);
            }
          }
        }
        if (freeCells.length > 0) {
          const idx = Math.floor(Math.random() * freeCells.length);
          food = freeCells[idx];
        }
      }

      function stopTimer() {
        if (timer !== null) {
          clearInterval(timer);
          timer = null;
        }
      }

      function startTimer() {
        stopTimer();
        if (!isAlive) return;
        timer = setInterval(() => {
          window.game.tick();
        }, 120);
      }

      function draw() {
        const canvas = document.getElementById('snake');
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        const cellSize = canvas.width / w;

        // Draw dark background
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Draw grid lines
        ctx.strokeStyle = '#1e293b';
        ctx.lineWidth = 1;
        for (let x = 0; x <= canvas.width; x += cellSize) {
          ctx.beginPath();
          ctx.moveTo(x, 0);
          ctx.lineTo(x, canvas.height);
          ctx.stroke();
        }
        for (let y = 0; y <= canvas.height; y += cellSize) {
          ctx.beginPath();
          ctx.moveTo(0, y);
          ctx.lineTo(canvas.width, y);
          ctx.stroke();
        }

        // Draw food
        if (food) {
          const [fx, fy] = food;
          const cx = fx * cellSize + cellSize / 2;
          const cy = fy * cellSize + cellSize / 2;
          const radius = (cellSize / 2) - 2;

          ctx.fillStyle = '#f43f5e';
          ctx.beginPath();
          ctx.arc(cx, cy, Math.max(1, radius), 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = '#fda4af';
          ctx.beginPath();
          ctx.arc(cx - radius / 3, cy - radius / 3, Math.max(1, radius / 3), 0, Math.PI * 2);
          ctx.fill();
        }

        // Draw snake
        for (let i = snakeSegments.length - 1; i >= 0; i--) {
          const [sx, sy] = snakeSegments[i];
          const x = sx * cellSize;
          const y = sy * cellSize;
          const isHead = (i === 0);

          if (isHead) {
            ctx.fillStyle = '#10b981';
            ctx.fillRect(x + 1, y + 1, cellSize - 2, cellSize - 2);

            // Eye details
            ctx.fillStyle = '#ffffff';
            let eye1X, eye1Y, eye2X, eye2Y;
            const eyeSize = 3;

            if (currentDir === 'right') {
              eye1X = x + cellSize - 6; eye1Y = y + 4;
              eye2X = x + cellSize - 6; eye2Y = y + cellSize - 7;
            } else if (currentDir === 'left') {
              eye1X = x + 3; eye1Y = y + 4;
              eye2X = x + 3; eye2Y = y + cellSize - 7;
            } else if (currentDir === 'up') {
              eye1X = x + 4; eye1Y = y + 3;
              eye2X = x + cellSize - 7; eye2Y = y + 3;
            } else {
              eye1X = x + 4; eye1Y = y + cellSize - 6;
              eye2X = x + cellSize - 7; eye2Y = y + cellSize - 6;
            }
            ctx.fillRect(eye1X, eye1Y, eyeSize, eyeSize);
            ctx.fillRect(eye2X, eye2Y, eyeSize, eyeSize);
          } else {
            ctx.fillStyle = '#34d399';
            ctx.fillRect(x + 1, y + 1, cellSize - 2, cellSize - 2);
          }
        }

        // Game Over overlay
        if (!isAlive) {
          ctx.fillStyle = 'rgba(15, 23, 42, 0.75)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          ctx.fillStyle = '#f87171';
          ctx.font = 'bold 26px sans-serif';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 12);

          ctx.fillStyle = '#94a3b8';
          ctx.font = '14px sans-serif';
          ctx.fillText('Press Reset to play again', canvas.width / 2, canvas.height / 2 + 20);
        }
      }

      window.game = {
        w: GRID_SIZE,
        h: GRID_SIZE,
        reset: function() {
          stopTimer();
          isAlive = true;
          currentScore = 0;
          currentDir = 'right';
          pendingDir = null;
          snakeSegments = [
            [10, 10],
            [9, 10],
            [8, 10]
          ];
          spawnFood();
          updateScoreUI();
          draw();
        },
        tick: function() {
          if (!isAlive) return;

          if (pendingDir) {
            currentDir = pendingDir;
            pendingDir = null;
          }

          const [headX, headY] = snakeSegments[0];
          let dx = 0, dy = 0;
          if (currentDir === 'up') dy = -1;
          else if (currentDir === 'down') dy = 1;
          else if (currentDir === 'left') dx = -1;
          else if (currentDir === 'right') dx = 1;

          const nextX = headX + dx;
          const nextY = headY + dy;

          // Wall collision
          if (nextX < 0 || nextX >= w || nextY < 0 || nextY >= h) {
            isAlive = false;
            stopTimer();
            draw();
            return;
          }

          const isEating = (food && nextX === food[0] && nextY === food[1]);

          if (isEating) {
            for (let i = 0; i < snakeSegments.length; i++) {
              if (snakeSegments[i][0] === nextX && snakeSegments[i][1] === nextY) {
                isAlive = false;
                stopTimer();
                draw();
                return;
              }
            }
            snakeSegments.unshift([nextX, nextY]);
            currentScore++;
            updateScoreUI();
            spawnFood();
          } else {
            snakeSegments.pop();
            for (let i = 0; i < snakeSegments.length; i++) {
              if (snakeSegments[i][0] === nextX && snakeSegments[i][1] === nextY) {
                isAlive = false;
                stopTimer();
                draw();
                return;
              }
            }
            snakeSegments.unshift([nextX, nextY]);
          }

          draw();
        },
        setDir: function(dir) {
          if (!dir || typeof dir !== 'string') return;
          const d = dir.toLowerCase();
          if (!['up', 'down', 'left', 'right'].includes(d)) return;

          const checkDir = pendingDir || currentDir;
          if (d !== OPPOSITES[checkDir]) {
            pendingDir = d;
          }
        },
        setFood: function(x, y) {
          food = [x, y];
          draw();
        },
        snake: function() {
          return snakeSegments.map(pt => [pt[0], pt[1]]);
        },
        food: function() {
          return food ? [food[0], food[1]] : null;
        },
        alive: function() {
          return isAlive;
        },
        score: function() {
          return currentScore;
        }
      };

      // Button Event Listeners
      document.getElementById('start').addEventListener('click', () => {
        if (!isAlive) window.game.reset();
        startTimer();
      });

      document.getElementById('pause').addEventListener('click', () => {
        stopTimer();
      });

      document.getElementById('reset').addEventListener('click', () => {
        window.game.reset();
      });

      // Keyboard Listeners
      window.addEventListener('keydown', (e) => {
        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '].includes(e.key)) {
          e.preventDefault();
        }

        if (e.key === 'ArrowUp' || e.key === 'w' || e.key === 'W') {
          window.game.setDir('up');
        } else if (e.key === 'ArrowDown' || e.key === 's' || e.key === 'S') {
          window.game.setDir('down');
        } else if (e.key === 'ArrowLeft' || e.key === 'a' || e.key === 'A') {
          window.game.setDir('left');
        } else if (e.key === 'ArrowRight' || e.key === 'd' || e.key === 'D') {
          window.game.setDir('right');
        } else if (e.key === ' ') {
          if (!isAlive) {
            window.game.reset();
            startTimer();
          } else if (timer) {
            stopTimer();
          } else {
            startTimer();
          }
        }
      });

      // Initialize game state on load
      window.game.reset();
    })();
  </script>
</body>
</html>
